class Solution:
    def minDeletionSize(self, strs):
        from itertools import combinations
        n = len(strs)
        if n <= 1:
            return 0
        W = len(strs[0])
        cols = list(range(W))
        for d in range(W + 1):
            for dele in combinations(cols, d):
                ds = set(dele)
                kept = [''.join(c for j, c in enumerate(row) if j not in ds) for row in strs]
                if all(kept[i] <= kept[i + 1] for i in range(n - 1)):
                    return d
        return W

