class Solution:
    def minDeletionSize(self, strs):
        n = len(strs)
        if n <= 1:
            return 0
        W = len(strs[0])
        settled = [False] * (n - 1)
        deletions = 0
        for j in range(W):
            bad = False
            for i in range(n - 1):
                if not settled[i] and strs[i][j] > strs[i + 1][j]:
                    bad = True
                    break
            if bad:
                deletions += 1
                continue
            for i in range(n - 1):
                if not settled[i] and strs[i][j] < strs[i + 1][j]:
                    settled[i] = True
        return deletions

