var minDeletionSize = function(strs) {
    const n = strs.length;
    if (n <= 1) return 0;
    const W = strs[0].length;
    const settled = new Array(n - 1).fill(false);
    let deletions = 0;
    for (let j = 0; j < W; j++) {
        let bad = false;
        for (let i = 0; i < n - 1; i++) {
            if (!settled[i] && strs[i][j] > strs[i + 1][j]) { bad = true; break; }
        }
        if (bad) { deletions++; continue; }
        for (let i = 0; i < n - 1; i++) {
            if (!settled[i] && strs[i][j] < strs[i + 1][j]) settled[i] = true;
        }
    }
    return deletions;
};
